class Solution {
public:
    int findComplement(int num) {
        if(!num) return 1;
        int mask=num;
        mask |= mask>>1; mask |= mask>>2; mask |= mask>>4;
        mask |= mask>>8; mask |= mask>>16;
        return num ^ mask;
    }
};

